import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { productAPI } from "../api";
import { useCart } from "../context/CartContext";

const ProductDetail = () => {
  const { slug } = useParams();
  const navigate = useNavigate();
  const { addToCart } = useCart();

  const [product, setProduct] = useState(null);
  const [related, setRelated] = useState([]);
  const [quantity, setQuantity] = useState(1);
  const [activeImage, setActiveImage] = useState("");
  const [loading, setLoading] = useState(true);

  // ==============================
  // 📌 1. Lấy thông tin sản phẩm
  // ==============================
  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await productAPI.getProductBySlug(slug);
        setProduct(res.data);

        // ảnh đầu tiên là ảnh chính
        setActiveImage(res.data.images?.[0]);

        // gọi sản phẩm liên quan
        const relatedRes = await productAPI.getRelated(res.data.category._id);
        setRelated(relatedRes.data.products);
      } catch (err) {
        console.error("Product fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [slug]);

  if (loading) return <p className="p-10">Đang tải sản phẩm...</p>;
  if (!product) return <p className="p-10 text-red-600">Không tìm thấy sản phẩm.</p>;

  // ==============================
  // 📌 2. Tính giá sau giảm
  // ==============================
  const finalPrice = product.discountPrice || product.price;

  // ==============================
  // 📌 3. Thêm vào giỏ
  // ==============================
  const handleAddCart = () => {
    addToCart(product, quantity);
  };

  // ==============================
  // 📌 4. Mua ngay
  // ==============================
  const handleBuyNow = () => {
    addToCart(product, quantity);
    navigate("/checkout");
  };

  // ==============================
  // 📌 5. Tăng giảm số lượng
  // ==============================
  const increaseQty = () => {
    if (quantity < product.stock) setQuantity(quantity + 1);
  };
  const decreaseQty = () => {
    if (quantity > 1) setQuantity(quantity - 1);
  };

  return (
    <div className="max-w-6xl mx-auto p-6 grid grid-cols-1 md:grid-cols-2 gap-10">
      {/* =============================
          🖼 PHẦN HÌNH ẢNH
      ============================= */}
      <div>
        <div className="w-full h-96 border rounded-xl overflow-hidden shadow-md">
          <img src={activeImage} alt="" className="w-full h-full object-cover" />
        </div>

        {/* Thumbnail */}
        <div className="flex gap-3 mt-4">
          {product.images?.map((img, i) => (
            <img
              key={i}
              src={img}
              onClick={() => setActiveImage(img)}
              className={`w-20 h-20 object-cover rounded-xl cursor-pointer border-2 ${
                activeImage === img ? "border-pink-500" : "border-gray-200"
              }`}
            />
          ))}
        </div>
      </div>

      {/* =============================
          📝 THÔNG TIN SẢN PHẨM
      ============================= */}
      <div>
        <h1 className="text-3xl font-semibold mb-3 text-[#374151]">{product.name}</h1>

        {/* Rating */}
        <div className="flex items-center gap-1 mb-2">
          <span className="text-yellow-400 text-xl">★</span>
          <span className="text-gray-600">{product.rating || 4.5} / 5</span>
          <span className="text-gray-400 text-sm">(120 đánh giá)</span>
        </div>

        {/* Giá */}
        <div className="flex items-end gap-4 mb-5">
          <span className="text-3xl font-bold text-pink-600">
            {finalPrice.toLocaleString()}đ
          </span>

          {product.discountPrice && (
            <span className="line-through text-gray-400">
              {product.price.toLocaleString()}đ
            </span>
          )}
        </div>

        <p className="text-gray-600 mb-4">{product.description}</p>

        {/* Badge giảm giá */}
        {product.discountPrice && (
          <p className="inline-block px-4 py-1 bg-pink-100 text-pink-600 rounded-full mb-4">
            🔥 Đang giảm giá {Math.round((1 - finalPrice / product.price) * 100)}%
          </p>
        )}

        {/* Số lượng */}
        <div className="flex items-center gap-4 my-5">
          <button className="px-3 py-2 bg-gray-200 rounded-lg" onClick={decreaseQty}>
            -
          </button>
          <span className="text-lg">{quantity}</span>
          <button className="px-3 py-2 bg-gray-200 rounded-lg" onClick={increaseQty}>
            +
          </button>

          <span className="text-gray-500 ml-3">
            {product.stock > 0 ? `${product.stock} sản phẩm có sẵn` : "Hết hàng"}
          </span>
        </div>

        {/* Nút mua */}
        <div className="flex gap-4 mt-6">
          <button
            onClick={handleAddCart}
            disabled={product.stock === 0}
            className="px-6 py-3 bg-yellow-400 hover:bg-yellow-500 rounded-lg font-semibold"
          >
            🛒 Thêm vào giỏ
          </button>

          <button
            onClick={handleBuyNow}
            disabled={product.stock === 0}
            className="px-6 py-3 bg-pink-600 hover:bg-pink-700 text-white rounded-lg font-semibold"
          >
            💖 Mua ngay
          </button>
        </div>

        {/* Chính sách */}
        <div className="mt-10 p-5 border rounded-xl bg-gray-50">
          <h3 className="font-semibold mb-3 text-gray-700">🌸 Chính sách của shop</h3>
          <ul className="space-y-2 text-gray-600">
            <li>🚚 Giao hàng trong 2 giờ</li>
            <li>🎀 Miễn phí thiệp & gói quà</li>
            <li>🔄 Đổi trả miễn phí trong 24h</li>
            <li>🎁 Giảm giá cho khách hàng cũ</li>
          </ul>
        </div>
      </div>

      {/* =============================
          🔗 SẢN PHẨM LIÊN QUAN
      ============================= */}
      <div className="col-span-2 mt-14">
        <h2 className="text-2xl font-semibold mb-4">Sản phẩm liên quan</h2>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
          {related.map((item) => (
            <div
              key={item._id}
              onClick={() => navigate(`/product/${item.slug}`)}
              className="cursor-pointer p-3 border rounded-xl hover:shadow-lg transition"
            >
              <img
                src={item.images?.[0]}
                className="h-40 w-full object-cover rounded-lg"
              />
              <h3 className="mt-2 font-medium">{item.name}</h3>
              <p className="text-pink-600 font-semibold">
                {item.price.toLocaleString()}đ
              </p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ProductDetail;
